const raw = $input.first().json;
const b = raw.body || raw;
if (b.message_type && b.message_type !== 'incoming') return [];
if (b.private) return [];

const conv = b.conversation || {};
const sender = conv?.meta?.sender || b.sender || {};
let phone = (sender.phone_number || sender.identifier || '').replace(/[^0-9+]/g,'').replace(/^\+/,'');
if (phone.startsWith('00')) phone = phone.slice(2);

const atts = b.attachments || b.message?.attachments || [];
let mediaType = 'text', mediaUrl = '';
if (atts.length) {
  const a = atts[0];
  mediaUrl = a.data_url || a.file_url || '';
  if ((a.file_type||'').includes('audio')) mediaType = 'voice';
  else if ((a.file_type||'').includes('image')) mediaType = 'image';
}

const text = (b.content || b.message?.content || '').trim();
if (!phone) return [];
if (mediaType === 'text' && !text) return [];

return [{ json: {
  client_id:  String(raw.client_id || b.client_id || ''),
  account_id: String(b.account?.id || conv?.account_id || ''),
  inbox_id:   String(b.inbox?.id || conv?.inbox_id || ''),
  convId:     conv?.id || null,
  phone, name: sender.name || '', text, mediaType, mediaUrl
} }];

const msg = $('Code · Parse').first().json;
const t = $input.first().json;
if (!t || !t.chatwoot_inbox_id) return []; // no tenant configured for this inbox
let flow = {}; try { flow = JSON.parse(t.flow_json || '{}'); } catch(e) {}
return [{ json: {
  ...msg,
  chatwoot_base: t.chatwoot_base, chatwoot_account_id: t.chatwoot_account_id, chatwoot_token: t.chatwoot_token,
  nocodb_base: t.nocodb_base, leads_table_id: t.leads_table_id, nocodb_token: t.nocodb_token,
  openrouter_key: t.openrouter_key, model: t.model || 'google/gemini-2.5-flash',
  language: t.language || 'ml', main_prompt: t.main_prompt || '', flow
} }];

const c = $('Code · Build ctx').first().json;
const r = $input.first().json;
const lead = (r.list && r.list[0]) ? r.list[0] : null;
if (lead && (lead.Handover === 'Yes' || lead.Stage === 'human_handover')) return []; // bot-off
return [{ json: { ...c, leadId: lead?.Id || null, stage: lead?.Stage || 'new' } }];

const c = $('Code · State').first().json;
const r = $input.first().json;
const txt = r.choices?.[0]?.message?.content || '(image received)';
return [{ json: { ...c, userText: txt } }];

const c = $('Code · State').first().json;
const r = $input.first().json;
const txt = r.choices?.[0]?.message?.content || '(voice note received)';
return [{ json: { ...c, userText: txt } }];

const c = $input.first().json;
const raw = c.choices?.[0]?.message?.content || '';
let intent = 'SHORT_NEUTRAL';
try { const m = raw.replace(/```json|```/gi,'').match(/\{[\s\S]*\}/); if (m) intent = JSON.parse(m[0]).intent || intent; } catch(e) {}
const valid = ['DELAY','BOOKING','AFFIRMATIVE','WATCHED','FORM_DONE','WANTS_MORE_INFO','QUESTION','WANTS_HUMAN','SHORT_NEUTRAL'];
if (!valid.includes(intent)) intent = 'SHORT_NEUTRAL';
// flow lookup
const flow = c.flow || {};
const node = (flow.stages && (flow.stages[c.stage] || flow.stages['new'])) || {};
const action = node[intent] || node['*'] || { next: c.stage, msg: null };
let route = 'stage';
if (intent === 'WANTS_HUMAN') route = 'human';
else if (intent === 'QUESTION') route = 'faq';
// build reply text for stage route
let reply = '';
let videoUrl = null;
if (route === 'stage' && action.msg) {
  const vars = flow.variables || {};
  reply = (flow.messages?.[action.msg] || '').replace(/\[(\w+)\]/g, (_,k)=> vars[k.toLowerCase()] ?? vars[k] ?? '');
  if (action.form && vars.form_link && !reply.includes(vars.form_link)) reply += '\n\n' + vars.form_link;
  if (action.video) videoUrl = vars[action.video] || null;
}
return [{ json: { ...$('Code · State').first().json, userText: c.userText, intent, route, next: action.next || c.stage, reply, videoUrl } }];

const c = $('Code · Intent + flow').first().json;
const r = $input.first().json;
const reply = r.choices?.[0]?.message?.content?.trim() || 'Sir/Madam, ഒരു moment 🙏';
return [{ json: { ...c, reply } }];

const c = $input.first().json;
const isHuman = c.route === 'human';
const body = { Phone: c.phone, Name: c.name, ConversationID: c.convId, Date: new Date().toISOString(), Language: c.language };
if (isHuman) { body.Stage = 'human_handover'; body.Handover = 'Yes'; }
else { body.Stage = c.next; }
if (!isHuman && c.next !== c.stage) { body['Follow up 1']='No'; body['Follow up 2']='No'; body['Follow up 3']='No'; }
const method = c.leadId ? 'PATCH' : 'POST';
if (c.leadId) body.Id = c.leadId;
return [{ json: { ...c, _method: method, _body: body } }];
